var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그 유명한 사이버 캣이 이런 꼬마라니 의외로군.","JPN":"あの有名なサイバーキャットが、こんな子どもだったとは意外だ。","ENG":"I'm surprised the infamous Cyber Cat is a little girl like this.","TWN":"沒想到那個著名的駭客竟然會是這種小孩子。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"꼬마는 해킹하면 안 된다는 법 있어? 얼른 변호사나 불러 줘.","JPN":"子どもがハッキングしちゃいけないわけ？　さっさと弁護士を呼んでちょうだい。","ENG":"Little girls can hack too, you know? Just get me my lawyer.","TWN":"誰規定小孩子不能當駭客的？我勸你趕緊找個律師吧。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"애초에 꼬마든 어른이든 해킹은 하면 안 되는 법이지.","JPN":"本来、子どもだろうが大人だろうがハッキングは違法だ。","ENG":"You shouldn't be hacking, regardless of your age.","TWN":"法律可不管妳是大人還是小孩，做駭客就是違法的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 자네가 변호사와 접견할 일은 없네.","JPN":"それに、君が弁護士と接見することはない。","ENG":"And you have no need for a lawyer.","TWN":"喔對了，妳也沒必要和律師見面了呢。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"국가 안보에 중대한 위협을 끼치는 사안이라면 재판 없이 처리할 수도 있거든.","JPN":"国家安保に重大な脅威を及ぼす事案であれば、裁判を介することなく処理できるのだ。","ENG":"For matters of grave national security threats, we can process you without trial.","TWN":"對國家安全造成巨大威脅的案件，是可以跳過審判直接進行處分的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"와, 진짜 악당 같은 소릴 하네. 국민을 이따위로 취급해도 되는 거야?","JPN":"わぁ、本物の悪党ね。国民をこんな風に扱っていいわけ？","ENG":"Wow, now you really sound like a villain. Come on, you can't treat me like this. I'm a citizen of the States!","TWN":"哇，聽起來像是個真反派在說話呢。\\n你把國民的人權當成什麼了?"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 내가 무슨 큰 죄를 지었다고 거기서 국가 안보가 튀어나와?","JPN":"それに、国家安保だとか何とか言ってるけど、アタシが何をしたって言うの？","ENG":"Besides, what have I ever done to be considered a national security threat?","TWN":"我又犯了什麼滔天大罪，能夠威脅到國家安全？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그냥 심심풀이 삼아 여기저기 기웃거리고 다닌 게 다라고!","JPN":"ただ暇つぶしに、あれこれ覗きに行っただけじゃない！","ENG":"All I did was snoop around a little because I was bored!","TWN":"我只是為了打發時間到處看看而已啊！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"자신의 상황을 전혀 이해하지 못하고 있는 것 같으니 예를 하나 들어 주지.","JPN":"自身の置かれている状況を全く理解できていないようだな。では簡単に説明してやろう。","ENG":"You don't seem to understand the situation you're in at all. So let me give you an example.","TWN":"妳似乎完全沒有理解自己的處境呢，我舉個例子吧。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"최근에 자네가 침식지대에 고립되어 있던 우리 측 부대원에게 탈출 경로를 제공해 준 적이 있지?","JPN":"最近、君が侵食地帯で孤立していた我々の隊員に、脱出経路を提供したことがあるだろう？","ENG":"Remember how you helped our troops out of a Corrupted Area recently by transmitting viable waypoints for them?","TWN":"最近妳是否為困在侵蝕地區的我方部隊提供了逃脫路線？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그, 그게 뭐 어때서?","JPN":"そ、それが何だって言うのよ……","ENG":"W-what about that?","TWN":"那，那又怎樣？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오히려 칭찬 받아야 할 일 아냐? 사람 목숨을 구해 줬잖아?","JPN":"むしろ、褒められるべきでしょ？　人の命を救ったんだから。","ENG":"If anything, shouldn't I get a medal for that? I saved lives, you know.","TWN":"你們反而應該來稱讚我吧？我可是救了人命啊！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"물론 그렇지. 그 과정에서 자네가 우리 첩보위성을 해킹하지 않았다면 말이야.","JPN":"もちろんそうだ。その過程で、君が我々の偵察衛星をハッキングしていなければな。","ENG":"Indeed. Except you hacked our ISR satellites in the process.","TWN":"確實如此。前提是妳沒有駭進我們的情報衛星裡。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니 그건......","JPN":"いや、それは……","ENG":"But...","TWN":"不，那是……"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그 외에도 수많은 기밀 자료와 정부 데이터베이스를 털어 왔더군.","JPN":"それ以外にも、多くの機密資料と政府データベースにアクセスしたようだな。","ENG":"And you also happened to break into countless classified files and the government databases.","TWN":"除此之外，妳還洩露了許多機密資料和公開了政府資料庫。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"거의 흔적이 남지 않아서 자네를 추적하는데 많은 고생을 해야 했네.","JPN":"痕跡がほぼ残っておらず、君まで辿り着くのにかなりの労力を費やした。","ENG":"It took monumental efforts tracking you down since you hardly left a trail.","TWN":"因為幾乎沒留下入侵痕跡，追蹤妳可是花了我們不少力氣。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};